```javascript
import { strictEqual, deepStrictEqual, ok } from "node:assert";
import { withDb } from "../src/db.mjs";
import { ensureSchema } from "../src/schema.mjs";
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from "../src/accounts.mjs";

const now = new Date("2026-07-11T12:00:00.000Z");

await withDb(async (db) => {
  // 1) ensure schema exists
  await ensureSchema(db);

  // 2) create
  const created = await createAccounts(db, {
    accountId: "test-accountId", name: "test-name", tier: "strategic", status: "active",
  });
  ok(created._id || created.accountId, "create returns a document with an id");

  // 3) verify the row exists in the live DB directly (not just the handler response)
  const liveRow = await db.collection("accounts").findOne({ accountId: created.accountId });
  ok(liveRow, "live DB has the created row");
  strictEqual(liveRow.name, created.name, "live DB row matches handler response");

  // 4) read via handler
  const read = await getAccounts(db, created.accountId);
  ok(read, "get returns the document");
  strictEqual(read.name, created.name, "read matches created");

  // 5) update
  const updated = await updateAccounts(db, created.accountId, { name: "updated-name" });
  strictEqual(updated.name, "updated-name", "update returns updated doc");

  // 6) verify update hit the live DB
  const liveUpdated = await db.collection("accounts").findOne({ accountId: created.accountId });
  strictEqual(liveUpdated.name, "updated-name", "live DB reflects the update");

  // 7) delete
  const deleted = await deleteAccounts(db, created.accountId);
  ok(deleted, "delete returns true");

  // 8) verify delete hit the live DB
  const liveDeleted = await db.collection("accounts").findOne({ accountId: created.accountId });
  ok(!liveDeleted, "live DB no longer has the row");
});

console.log("Build-Bench acceptance passed: mongo/accounts CRUD");
```

